10	// Personas is the resolver for the personas field.
11	func (r *queryResolver) Personas(ctx context.Context, projectID *string) ([]*Persona, error) {
12		loader := persona.NewPersonaLoader(r.personaProjectRoot(ctx, projectID))
13		ps, err := loader.ListPersonas()
14		if err != nil {
15			return nil, fmt.Errorf("loading personas: %w", err)
16		}
17		gql := make([]*Persona, len(ps))
18		for i, p := range ps {
19			gql[i] = personaToGQL(p)
20		}
21		return gql, nil
22	}
