24	// Persona is the resolver for the persona field.
25	func (r *queryResolver) Persona(ctx context.Context, name string, projectID *string) (*Persona, error) {
26		loader := persona.NewPersonaLoader(r.personaProjectRoot(ctx, projectID))
27		p, err := loader.LoadPersona(name)
28		if err != nil {
29			return nil, nil //nolint:nilerr // not-found is represented as null
30		}
31		return personaToGQL(p), nil
32	}
