267	// cloneProviderModelsResult deep-copies a result so cached entries are not
268	// mutated when callers flip FromCache or a future field.
269	func cloneProviderModelsResult(in *ProviderModelsResult) *ProviderModelsResult {
270		if in == nil {
271			return nil
272		}
273		out := *in
274		if in.Models != nil {
275			out.Models = make([]*ProviderModelEntry, 0, len(in.Models))
276			for _, m := range in.Models {
277				if m == nil {
278					continue
279				}
280				mc := *m
281				if m.ContextLength != nil {
282					v := *m.ContextLength
283					mc.ContextLength = &v
284				}
285				out.Models = append(out.Models, &mc)
286			}
287		}
288		return &out
289	}

